const text = $input.first().json.output || 
             $input.first().json.text || 
             JSON.stringify($input.first().json);

return [
  {
    json: {
      project: {
        raw_plan: text,
        project_name: "",
        description: "",
        features: [],
        modules: [],
        tech_stack: {},
        architecture: {},
        tasks: [],
        backend: {},
        frontend: {},
        database: {},
        tests: {},
        documentation: {}
      }
    }
  }
];;

const project = $input.first().json.project || {};

let text =
  $input.first().json.output ??
  $input.first().json.text ??
  "";

text = text.trim();

// Remove markdown
text = text.replace(/^```json\s*/i, "");
text = text.replace(/^```\s*/i, "");
text = text.replace(/\s*```$/i, "");

// Auto-fix missing closing braces
const openBraces = (text.match(/{/g) || []).length;
const closeBraces = (text.match(/}/g) || []).length;

if (closeBraces < openBraces) {
  text += "}".repeat(openBraces - closeBraces);
}

project.architecture = JSON.parse(text);

return [
  {
    json: {
      project
    }
  }
];

