return $input.all().map((item, index) => {

    let output = item.json.output || "";

    // Remove surrounding markdown if entire response is fenced
    output = output.trim();
    output = output.replace(/^```(?:json|jsx|tsx|js|py|python|sql|md)?\s*/i, "");
    output = output.replace(/\s*```$/i, "");

    // -------- Extract PATH --------
    let path = "";

    const pathMatch = output.match(/PATH:\s*([^\n\r]+)/i);

    if (pathMatch) {
        path = pathMatch[1].trim();
    } else if (item.json.targetFile) {
        // fallback from planner
        path = item.json.targetFile;
    }

    // -------- Extract CODE --------
    let code = output;

    const codeIndex = output.search(/CODE:/i);

    if (codeIndex >= 0) {
        code = output.substring(codeIndex + 5).trim();
    }

    // Remove code fences inside CODE
    code = code.replace(/^```(?:jsx|tsx|js|py|python|sql|md)?\s*/i, "");
    code = code.replace(/\s*```$/i, "");

    code = code.trim();

    return {
        json: {
            path,
            code
        }
    };

});

return $input.all().map(item => {

    let path = item.json.path || item.json.targetFile || "";

    let code = item.json.code || item.json.output || "";

    // Remove markdown fences
    code = code.replace(/^```[a-zA-Z]*\n?/i, "");
    code = code.replace(/\n?```$/i, "");

    // Remove extra blank lines
    code = code.trim();

    return {
        json: {
            path,
            code
        }
    };

});

