let text = $input.first().json.output;

text = text.replace(/^```json\s*/i, "");
text = text.replace(/\s*```$/i, "");

return [
  {
    json: JSON.parse(text)
  }
];

const fileMap = new Map();

for (const item of $input.all()) {
  const path = item.json.path?.trim();
  const code = item.json.code?.trim();

  if (!path || !code) continue;

  fileMap.set(path, {
    path,
    code
  });
}

return [...fileMap.values()].map(file => ({
  json: file
}));

const errors = [];
const files = [];

for (const item of $input.all()) {

    const { path, code } = item.json;

    if (!path)
        errors.push("Missing path");

    if (!code)
        errors.push(`${path} has no code`);

    if (code.includes("```"))
        errors.push(`${path} still contains markdown`);

    if (code.startsWith("PATH:"))
        errors.push(`${path} still contains PATH label`);

    files.push(item.json);
}

return [
{
json:{
    files,
    errors
}
}
];
